{
    w_stvec((uint64)trap_vector);
    timer_setNext(false);
    intr_on(); // S态总中断开启
}

// 外设中断处理
void external_interrupt_handler()
{
    int irq = plic_claim();
    switch(irq) {
        case UART_IRQ:
            uart_intr();
            break;
        case VIO_IRQ:
            virtio_disk_intr();
            break;
        default:
            panic("unkown irq\n");
            break;
    }
    if(irq) plic_complete(irq);
}

// 时钟中断处理
void timer_interrupt_handler(bool inkernel)
{
