// 文件系统操作集合
FS_OP_t FS_OP;

// 虚拟文件描述符管理
#define VFILE_FD_BASE 1000
#define MAX_VFILES 32

typedef struct {
    bool in_use;
    char path[PATH_LEN];
    int offset;
} vfile_t;

static vfile_t vfiles[MAX_VFILES];

// 分配虚拟文件描述符
static int alloc_vfd(const char* path)
{
    for (int i = 0; i < MAX_VFILES; i++) {
        if (!vfiles[i].in_use) {
            vfiles[i].in_use = true;
            strncpy(vfiles[i].path, path, PATH_LEN - 1);
            vfiles[i].path[PATH_LEN - 1] = '\0';
            vfiles[i].offset = 0;
            return VFILE_FD_BASE + i;
        }
    }
    return -1;
}

// 释放虚拟文件描述符
static void free_vfd(int fd)
{
    int idx = fd - VFILE_FD_BASE;
    if (idx >= 0 && idx < MAX_VFILES) {
        vfiles[idx].in_use = false;
    }
}

// 检查是否为虚拟文件描述符
static bool is_vfd(int fd)
{
    return fd >= VFILE_FD_BASE && fd < VFILE_FD_BASE + MAX_VFILES;
}

// 获取虚拟文件信息
static vfile_t* get_vfile(int fd)
{
    int idx = fd - VFILE_FD_BASE;
    if (idx >= 0 && idx < MAX_VFILES && vfiles[idx].in_use) {
        return &vfiles[idx];
    }
    return NULL;
}

// 获取当前工作目录
// char* buf 用于存放工作目录的字符串
// int size  buf的大小
// 成功返回buf的指针, 失败返回NULL 
uint64 sys_getcwd()
{
    uint64 dst;
    int size;
    arg_addr(0, &dst);
    arg_int(1, &size);

    return FS_OP.fs_getcwd(dst, size);
}

// 切换工作目录
// char* path 要切换到的目录
// 成功返回0 失败返回-1
uint64 sys_chdir()
{
    char path[PATH_LEN];
    if(arg_str(0, path, PATH_LEN) < 0) 
        return -1;

    return FS_OP.fs_chdir(path);
}

// 按条目获取目录的内容
// int fd  要读取的目录名
// dirent_t* buf  保存目录信息的缓冲区
// int len  缓存区的大小
// 成功返回读取的字节数 失败返回-1 
uint64 sys_getdents64()
{

    int fd, size;
    uint64 dst;
    arg_int(0, &fd);
    if(fd != FD_CWD && (fd < 0 || fd >= NOFILE))
        return -1;
    arg_addr(1, &dst);
    arg_int(2, &size);

    return FS_OP.fs_getdents64(fd, dst, size);
}

// 创建目录文件
// int dirfd       要创建的目录文件所在目录的描述符
// char* path      要创建的目录文件的路径(规则见sys_read)
// mode_t mode     文件所有权(忽略)
// 成功返回0 失败返回-1
uint64 sys_mkdirat()
{
    int fd, mode;
    char path[PATH_LEN];
    path[PATH_LEN - 1] = '\0';

    arg_int(0, &fd);
    if(fd != FD_CWD && (fd < 0 || fd >= NOFILE))
        return -1;    
    if(arg_str(1, path, PATH_LEN - 1) < 0)
        return -1;
    arg_int(3, &mode);

    return FS_OP.fs_mkdirat(fd, path, (uint16)mode);
}

// 打开或创建一个文件
// int fd 文件所在目录的描述符
// char* path 目标文件的路径
// int flags 访问模式
// mode_t mode 文件所有权(暂时忽略)
// 1. 路径是绝对路径则忽略fd
// 2. 路径是相对路径且fd=-100   说明相对于cwd
// 3. 路径是相对路径且fd是合法值 说明相对于fd指向的路径
// 成功返回打开或创建的文件的描述符fd 失败返回-1 
uint64 sys_openat()
{
    int fd, flags, mode;   
    char path[PATH_LEN];
    path[PATH_LEN - 1] = '\0';

    arg_int(0, &fd);
    if(fd != FD_CWD && (fd < 0 || fd >= NOFILE))
        return -1;    
    if(arg_str(1, path, PATH_LEN - 1) < 0)
        return -1;
    arg_int(2, &flags);
    arg_int(3, &mode);

    // 检查是否为虚拟文件
    if (procfs_is_virtual(path)) {
        // 分配虚拟文件描述符
        return alloc_vfd(path);
    }

    return FS_OP.fs_openat(fd, path, flags, (uint16)mode);
}

// 关闭一个文件
// int fd 需要关闭的文件的描述符
// 成功返回0 失败返回-1
uint64 sys_close()
{
    int fd;
    arg_int(0, &fd);
    if(fd < 0 || fd >= NOFILE) {
        // 检查是否为虚拟文件描述符
        if (is_vfd(fd)) {
            free_vfd(fd);
            return 0;
        }
        return -1;
    }

    return FS_OP.fs_close(fd);
}

// 文件指针移动
// int fd
// uin32 offset
// int whence
uint64 sys_lseek()
{
    int fd, whence;
    uint64 offset;

    arg_int(0, &fd);
    arg_addr(1, &offset);
    arg_int(2, &whence);

    if(fd < 0 || fd >= NOFILE)
        return -1;

    return FS_OP.fs_lseek(fd, offset, whence);
}

// 文件读取
// int fd    目标文件描述符
// char* buf 读取内容的缓存区
// int count 读取的字节数
// 成功返回读取字节数 失败返回-1
uint64 sys_read()
{
    int fd, len;
    uint64 dst;

    arg_int(0, &fd);
    if(fd < 0 || fd >= NOFILE) {
        // 检查是否为虚拟文件描述符
        if (is_vfd(fd)) {
            vfile_t* vf = get_vfile(fd);
            if (!vf) return -1;

            arg_addr(1, &dst);
            arg_int(2, &len);

            char* buf = (char*)pmem_alloc_pages(1, true);
            if (!buf) return -1;

            int ret = procfs_read(vf->path, buf, len, vf->offset);
            if (ret > 0) {
                if (uvm_copyout(myproc()->pagetable, dst, (uint64)buf, ret) < 0) {
                    ret = -1;
                } else {
                    vf->offset += ret;
                }
            }

            pmem_free_pages(buf, 1, true);
            return ret;
        }
        return -1;
    }
    arg_addr(1, &dst);
    arg_int(2, &len);

    return FS_OP.fs_read(fd, dst, len);    
}

// 文件写入
// int fd     目标文件描述符
// char* buf  写入的内容
// int count  写入的字节数
// 成功返回写入的字节数 失败返回-1
uint64 sys_write()
{
    int fd, len;
    uint64 src;

    arg_int(0, &fd);
    if(fd < 0 || fd >= NOFILE) {
        // 检查是否为虚拟文件描述符
        if (is_vfd(fd)) {
            vfile_t* vf = get_vfile(fd);
            if (!vf) return -1;

            arg_addr(1, &src);
            arg_int(2, &len);

            char* buf = (char*)pmem_alloc_pages(1, true);
            if (!buf) return -1;

            if (uvm_copyin(myproc()->pagetable, (uint64)buf, src, len) < 0) {
                pmem_free_pages(buf, 1, true);
                return -1;
            }

            int ret = procfs_write(vf->path, buf, len, vf->offset);
            if (ret > 0) {
                vf->offset += ret;
            }

            pmem_free_pages(buf, 1, true);
            return ret;
        }
        return -1;
    }
    arg_addr(1, &src);
    arg_int(2, &len);

    return FS_OP.fs_write(fd, src, len);
}


