        // 找到目标
        de.name[de.name_len] = '\0';
        if(strncmp(filename, de.name, EXT4_NAME_LEN) == 0) {
            ip = ext4_inode_get();
            sleeplock_acquire(&ip->lk);

            ip->inum = de.inum;
